// Nœud B — Decode Binary → JSON (No-FS)
// Remplace "Extract From File" qui encapsule sous une clé "data" parasite
// Retourne le JSON de la fiche directement à la racine pour le Nœud 2

const binaryData = $input.item.binary.data;
const raw = Buffer.from(binaryData.data, 'base64').toString('utf-8');
return { json: JSON.parse(raw) };

// ══════════════════════════════════════════════════════════════════════════
// NŒUD 2 — MEPA V6.2 No-FS (V6.3 FORTIFIÉ) : Audit de Conformité COMPLET
// Correctif A6 — 2026-03-16 : Réintégration C7, C9, C10, C11
// Contrôles actifs : C1-C13 (C13 en premier — détection NC)
// Sorties : VALIDE | INVALIDE | DONNEES_INSUFFISANTES
// ══════════════════════════════════════════════════════════════════════════

"use strict";

const fiche = $input.item.json;
const MEPA_SCRIPTS_DIR = $env.MEPA_SCRIPTS_DIR || "/data/mepa/scripts";

// ── Chargement mepa_constants.json via env ─────────────────────────────────
let CONSTANTS = null;
try {
  const rawConstants = $env.MEPA_CONSTANTS_JSON;
  if (rawConstants) CONSTANTS = JSON.parse(rawConstants);
} catch (_) { CONSTANTS = null; }

// ── Constantes embarquées (fallback BUG-007 inclus — 9 labels) ────────────
const LABELS_D4 = (CONSTANTS?.labels_trajectoire_d4?.labels) || [
  "(a) Rupture transformatrice",
  "(b) Répression réussie",
  "(c) Stase / ambigu",
  "(d) Effondrement progressif",
  "(d) Dissolution",
  "(e) Réforme institutionnelle",
  "(h) Stabilité",
  "(h)/(e) Stabilité ou réforme lente",
  "(γ) Transformation forcée",
];

const BORNES_CMD = (CONSTANTS?.bornes_commandes) || {
  T:{min:0,max:2},Mob:{min:0,max:1},R:{min:0,max:10},Ref:{min:0,max:1},
  Rc:{min:0,max:1},Rn:{min:0,max:1},E:{min:0,max:1},gamma:{min:0,max:1},
  EROI:{min:1.01,max:200},Pop:{min:0,max:10}
};

const NC_BLOQUANTES = new Set(
  CONSTANTS?.nc_protocol?.variables_nc_bloquantes ||
  ["E_split","gamma","EROI","Sa"]
);

// ── C9 : Whitelist clés racine autorisées ──────────────────────────────────
const RACINE_AUTORISEES = new Set([
  "$schema","$description","$statut","$audit",
  "$arbitrage","$note_archive","$note_correction",
  "wp_id","cas","periode","cluster","cluster_libelle","cluster_note",
  "trajectoire_attendue","trajectoire_attendue_libelle","trajectoire_forcee",
  "sa","sa_type_todd","sa_p6_modulation","sa_note",
  "sources_utilisees","variables",
  "conditions_initiales","conditions_initiales_finales",
  "commandes","commandes_finales","cmd_linear",
  "parametres_simulation","alertes_actives","alertes_conv_a",
  "defi_mepa","params_p",
  "raison_loi_physique","zone_stratification","t_max","theta_C","theta_I",
  "date_codage","codeur","statut",
  "_conv_e_meta","_pipeline_message",  // métadonnées pipeline CONV-E
  "cleanup","message"  // métadonnées nœud C nettoyage /tmp/
]);

// ── C10 : Contraintes spécifiques par WP ──────────────────────────────────
const CONTRAINTES_WP = {
  "WP-C1-1":  { EROI_max: 2.5,  cmd_linear_requis: true  },
  "WP-C4-1":  { EROI_max: 2.0                            },
  "WP-F1-1":  { cmd_linear_requis: true                  },
  "WP-F2-1":  { cmd_linear_requis: true, A_r_ne_max: 0.00},
  "WP-F3-1":  { cmd_linear_requis: true                  },
  "WP-F10-1": { t_max: 80                                },
  "WP-I10-1": { cmd_linear_requis: true                  },
  // WP-EXT : hors corpus principal V6.2 — reconnu si injecté pour test P5
  "WP-EXT-5": { EROI_min: 30, note: "Islande — étalon (e). Sa=2 nucléaire absolu. Hors 27 WP. Candidat V7." },
};

const CMD_OBLIGATOIRES = ["T","Mob","R","Ref","Rc","Rn","E","gamma","EROI","Pop"];
const THETA_C = {min:0.10, max:0.60};
const THETA_I = {min:0.05, max:0.50};
const SA_VALIDES = new Set([2,4,6,7]);

const erreurs  = [];
const warnings = [];

function _isNC(val) { return typeof val === "string" && val.trim().toUpperCase() === "NC"; }
function _toNum(val) {
  if (_isNC(val) || val === null || val === undefined) return null;
  const n = Number(val); return isNaN(n) ? null : n;
}

// ── C13 [PREMIER] — Détection NC bloquant ─────────────────────────────────
const cmd  = fiche.cmd || fiche.commandes || {};
const vars = fiche.variables || {};
const nc_bl  = [];
const nc_nbl = [];

for (const [k, v] of Object.entries({ ...cmd, ...vars })) {
  if (_isNC(v)) {
    if (NC_BLOQUANTES.has(k)) nc_bl.push(k);
    else nc_nbl.push(k);
  }
}

if (nc_bl.length > 0) {
  return [{
    json: {
      statut_audit:      "DONNEES_INSUFFISANTES",
      wp_id:             fiche.wp_id || "?",
      nb_erreurs:        0,
      nc_bloquantes:     nc_bl,
      nc_non_bloquantes: nc_nbl,
      audit_log: { statut: "DONNEES_INSUFFISANTES", erreurs: [], warnings: [], controles: { C13: "FAIL_BLOQUANT" } },
      message: `[NC BLOQUANT] Variables insuffisantes : ${nc_bl.join(", ")}`
    }
  }];
}

// ── C1 — Champs obligatoires ──────────────────────────────────────────────
let ok = true;
for (const f of ["wp_id","sa","t_max","theta_C","theta_I"]) {
  if (fiche[f] === undefined || fiche[f] === null) {
    erreurs.push(`C1 - Champ obligatoire manquant : '${f}'`); ok = false;
  }
}

// ── C2 — Clés cmd obligatoires ────────────────────────────────────────────
for (const k of CMD_OBLIGATOIRES) {
  if (!(k in cmd)) { erreurs.push(`C2 - Clé cmd manquante : '${k}'`); ok = false; }
}

// ── C3 — Plages physiques ─────────────────────────────────────────────────
for (const [k, v] of Object.entries(cmd)) {
  const num = _toNum(v);
  if (num === null) continue;
  const b = BORNES_CMD[k];
  if (b && (num < b.min || num > b.max)) {
    erreurs.push(`C3 - ${k}=${num} hors bornes [${b.min},${b.max}]`); ok = false;
  }
}

// ── C4 — Nomenclature D6 : 'gamma' présent, 'g' absent ───────────────────
if ("g" in cmd)     { erreurs.push("C4 - Clé 'g' dans cmd. Utiliser 'gamma'."); ok = false; }
if (!("gamma" in cmd)) { erreurs.push("C4 - Clé 'gamma' absente."); ok = false; }

// ── C5 — Labels D4 ───────────────────────────────────────────────────────
const traj = fiche.trajectoire_attendue;
if (traj && !LABELS_D4.includes(traj)) {
  erreurs.push(`C5 - Label D4 non conforme : '${traj}'. Valides : ${LABELS_D4.join(" | ")}`);
  ok = false;
}

// ── C6 — Sa valide ───────────────────────────────────────────────────────
const sa = parseInt(fiche.sa);
if (!SA_VALIDES.has(sa)) { erreurs.push(`C6 - Sa=${sa} invalide (valides: 2,4,6,7)`); ok = false; }

// ── C7 — Sa=7 : sa_p6_modulation documenté ───────────────────────────────
if (sa === 7) {
  const p6_flag = fiche.sa_p6_modulation === true || fiche.sa_p6_modulation === "true";
  if (!p6_flag) {
    warnings.push("C7 - Sa=7 : sa_p6_modulation non documenté. Runner applique p6×1.5 automatiquement (règle absolue V6.2).");
  }
}

// ── C8 — theta_C / theta_I dans plages ───────────────────────────────────
const tc = _toNum(fiche.theta_C);
const ti = _toNum(fiche.theta_I);
if (tc !== null && (tc < THETA_C.min || tc > THETA_C.max))
  erreurs.push(`C8 - theta_C=${tc} hors [${THETA_C.min},${THETA_C.max}]`);
if (ti !== null && (ti < THETA_I.min || ti > THETA_I.max))
  erreurs.push(`C8 - theta_I=${ti} hors [${THETA_I.min},${THETA_I.max}]`);

// ── C9 — Whitelist clés racine (exécuté APRÈS C13) ───────────────────────
const cles_extra = Object.keys(fiche).filter(k => !RACINE_AUTORISEES.has(k));
if (cles_extra.length > 0) {
  erreurs.push(`C9 - Clés non autorisées à la racine : [${cles_extra.join(", ")}]`);
  ok = false;
}

// ── C10 — Contraintes spécifiques par WP ─────────────────────────────────
const wp_id = fiche.wp_id || "WP-INCONNU";
if (wp_id && CONTRAINTES_WP[wp_id]) {
  const ctr  = CONTRAINTES_WP[wp_id];
  const eroi = _toNum(cmd.EROI);
  const rn   = _toNum(cmd.Rn);
  if (ctr.EROI_max !== undefined && eroi !== null && eroi > ctr.EROI_max) {
    erreurs.push(`C10 - ${wp_id} : EROI=${eroi} > max autorisé ${ctr.EROI_max}`); ok = false;
  }
  if (ctr.A_r_ne_max !== undefined && rn !== null && rn > ctr.A_r_ne_max) {
    erreurs.push(`C10 - ${wp_id} : Rn=${rn} > A_r_ne_max=${ctr.A_r_ne_max}`); ok = false;
  }
  if (ctr.t_max !== undefined && fiche.t_max !== undefined && fiche.t_max !== ctr.t_max) {
    warnings.push(`C10 - ${wp_id} : t_max=${fiche.t_max}, valeur recommandée=${ctr.t_max}`);
  }
}

// ── C11 — cmd_linear obligatoire pour Cluster C1 ─────────────────────────
const cluster = fiche.cluster || "";
const has_cmd_linear = fiche.cmd_linear != null
  && typeof fiche.cmd_linear === "object"
  && Object.keys(fiche.cmd_linear).filter(k => k !== "note").length > 0;
if (cluster === "C1" && !has_cmd_linear) {
  erreurs.push("C11 - Cluster C1 : cmd_linear.EROI obligatoire ({start, end}). Absent.");
  ok = false;
}

// ── C12 — Sa = entier ────────────────────────────────────────────────────
if (typeof fiche.sa !== "number" && isNaN(parseInt(fiche.sa)))
  erreurs.push("C12 - Sa doit être un entier.");

if (nc_nbl.length > 0)
  warnings.push(`NC non-bloquantes : ${nc_nbl.join(", ")} — fallbacks appliqués.`);

// ── Construction runner_config ────────────────────────────────────────────
const P_DEFAULTS = {
  p1:0.08, p2:0.045, p2b:0.06, p3:0.02, p4:0.4, p5:0.05,
  p6:0.12, p7:0.04, p8:0.03, p9:0.06, p10:0.8,
  p11a:0.6, p11b:0.15, p13:1.2, lam:0.68, mu:0.38, nu:0.62, rho:0.06
};
const params_runner = {
  ...P_DEFAULTS,
  ...(fiche.parametres_simulation || fiche.params || {}),
  theta_C: tc || 0.30,
  theta_I: ti || 0.22
};
const configPath = `/tmp/${wp_id}_runner_config.json`;
const resultPath = `/tmp/${wp_id}_result.json`;
const n1Path     = `/tmp/${wp_id}_n1_sensitivity.json`;

const runner_config = {
  wp_id,
  cas:                  fiche.cas || "",
  cluster,
  trajectoire_attendue: fiche.trajectoire_attendue || "",
  sa,
  y0:                   fiche.conditions_initiales || fiche.y0 || {},
  t_max:                fiche.t_max || 300,
  theta_C:              tc || 0.30,
  theta_I:              ti || 0.22,
  cmd,
  cmd_linear:           Object.fromEntries(
    Object.entries(fiche.cmd_linear || {}).filter(([k]) => k !== "note")
  ),
  params:               params_runner,
};

const llm_context = {
  wp_id, cluster, sa,
  cas:                  fiche.cas || "",
  periode:              fiche.periode || "",
  trajectoire_attendue: fiche.trajectoire_attendue || "",
  mepa_full_vars:       vars,
  defi_mepa:            fiche.defi_mepa || "",
  alertes:              fiche.alertes_conv_a || fiche.alertes || [],
  gamma:                cmd.gamma,
};

const statut = erreurs.length === 0 ? "VALIDE" : "INVALIDE";
const runner_cmd = `/usr/bin/python3 ${MEPA_SCRIPTS_DIR}/mepa_runner_v2_gamma.py ${configPath}`;
const n1_cmd     = `/usr/bin/python3 ${MEPA_SCRIPTS_DIR}/mepa_sensitivity_n1.py ${configPath} ${n1Path}`;

return [{
  json: {
    statut_audit:        statut,
    wp_id,
    nb_erreurs:          erreurs.length,
    nc_bloquantes:       nc_bl,
    nc_non_bloquantes:   nc_nbl,
    runner_config_json:  JSON.stringify(runner_config),
    runner_config_path:  configPath,
    result_path:         resultPath,
    n1_path:             n1Path,
    runner_cmd,
    n1_cmd,
    llm_context,
    audit_log: {
      statut, erreurs, warnings,
      controles: {
        C1:  !erreurs.some(e=>e.startsWith("C1")),
        C2:  !erreurs.some(e=>e.startsWith("C2")),
        C3:  !erreurs.some(e=>e.startsWith("C3")),
        C4:  !erreurs.some(e=>e.startsWith("C4")),
        C5:  !erreurs.some(e=>e.startsWith("C5")),
        C6:  !erreurs.some(e=>e.startsWith("C6")),
        C7:  warnings.some(w=>w.startsWith("C7")) ? "WARN" : "OK",
        C8:  !erreurs.some(e=>e.startsWith("C8")),
        C9:  !erreurs.some(e=>e.startsWith("C9")),
        C10: !erreurs.some(e=>e.startsWith("C10")),
        C11: !erreurs.some(e=>e.startsWith("C11")),
        C12: !erreurs.some(e=>e.startsWith("C12")),
        C13: "OK"
      }
    },
    message: statut === "VALIDE"
      ? `[VALIDE] ${wp_id} — audit C1-C13 OK${nc_nbl.length ? ` (NC non-bl: ${nc_nbl.join(",")})` : ""}`
      : `[INVALIDE] ${wp_id} — ${erreurs.length} erreur(s)`
  }
}];

// NŒUD ALERTE — Pipeline suspendu (fiche INVALIDE)
// Retourne le payload d'erreur pour notification CONV-B / Architecte

"use strict";
const data   = $input.item.json;
const wp_id  = data.wp_id || "?";
const audit  = data.audit_log || {};

return {
  json: {
    status:       "PIPELINE_SUSPENDU",
    wp_id,
    motif:        "INVALIDE",
    nb_erreurs:   data.nb_erreurs || 0,
    erreurs:      audit.erreurs   || [],
    warnings:     audit.warnings  || [],
    controles:    audit.controles || {},
    action_requise: "Recodage CONV-E — corriger les erreurs structurelles avant relance.",
    message:      `[PIPELINE STOP] ${wp_id} — ${data.nb_erreurs} erreur(s). ${data.message || ""}`
  }
};

// NŒUD ALERTE NC — Pipeline suspendu (DONNEES_INSUFFISANTES)
// Distinct de INVALIDE : la fiche est bien formée, les sources sont insuffisantes

"use strict";
const data  = $input.item.json;
const wp_id = data.wp_id || "?";

return {
  json: {
    status:       "PIPELINE_SUSPENDU",
    wp_id,
    motif:        "DONNEES_INSUFFISANTES",
    nc_bloquantes:    data.nc_bloquantes    || [],
    nc_non_bloquantes: data.nc_non_bloquantes || [],
    action_requise: (
      "Escalade Architecte. " +
      "Enrichissement des sources historiques requis pour : " +
      (data.nc_bloquantes || []).join(", ") +
      ". La fiche est structurellement valide (pas de recodage CONV-E)."
    ),
    message: `[NC BLOQUANT] ${wp_id} — ${data.message || ""}`
  }
};

// NOEUD 8a -- CONV-B Codage Independant + CCI (PRE-SIMULATION)
// Guide Survie Etape 1b+2 : CONV-B code en parallele, CCI AVANT simulation
// Les valeurs resolues serviront d'entree au runner
"use strict";
const https = require("https");
const { execSync } = require("child_process");
const fs    = require("fs");

const data   = $input.item.json;
const wp_id  = data.wp_id;
const ANTHROPIC_API_KEY = $env.ANTHROPIC_API_KEY;
const SCRIPTS = $env.MEPA_SCRIPTS_DIR || "/data/mepa/scripts";

const fiche_input = data.llm_context?.mepa_full_vars || {};
const cas     = data.llm_context?.cas     || "";
const periode = data.llm_context?.periode || "";
const cluster = data.llm_context?.cluster || "";

// Sources neutralisees : sans scores CONV-E, sans justifications
const sources_neutres = JSON.stringify(
  Object.fromEntries(
    Object.entries(fiche_input).map(([k, v]) => [
      k, { echelle: v.echelle, origine: v.origine,
           source_id: v.source_id, niveau_source: v.niveau_source,
           // sanity_check.valeur_indicateur supprimé — brise le double aveugle
           sanity_check: v.sanity_check ? { indicateur: v.sanity_check.indicateur } : null }
    ])
  )
);

// Variables hardcodees (EROI, Sa, A_r_ne si V6.2 normative)
const vars_hardcodees = Object.fromEntries(
  Object.entries(fiche_input)
    .filter(([k, v]) => v.valeur !== null && v.valeur !== undefined
                     && (v.source_id?.includes('hardcod') || v.source_id?.includes('normative') || v.source_id?.includes('V6.2')))
    .map(([k, v]) => [k, v.valeur])
);

const SYSTEM = `Tu es CONV-B, l'Auditeur Scientifique MEPA V6.2.
Tu codes independamment les 9 variables critiques du WP.
Tu ne vois PAS les scores de CONV-E. Double aveugle strict.

VARIABLES HARDCODEES (ne pas recoder, marquer accord=true) :
${JSON.stringify(vars_hardcodees)}

GRILLE D'ANCRAGE V6.2 :
E_split [0,1] : 0.0-0.2=cohesion, 0.4-0.6=fracture naissante, 0.8-1.0=fracture critique
gamma [0,1] : 0.0-0.2=desorganise, 0.4-0.6=organisation partielle, 0.8-1.0=forte
A_d_eff [0,10] : 0-2=effondrement, 4-6=trappe, 8-10=surplus
A_r_c [0,1] : 0.0-0.2=absente, 0.4-0.6=selective, 0.8-1.0=massive
A_r_ne [0,1] : 0.0-0.2=absente, 0.4-0.6=partielle, 0.8-1.0=totale
Cs [0,1] : 0.0-0.2=effondree, 0.4-0.6=contestee, 0.8-1.0=solide
L_t [0,1] : 0.0-0.2=effondree, 0.4-0.6=conditionnelle, 0.8-1.0=solide
EROI [valeur reelle] : <3=effondrement, 3-5=critique, 5-10=standard, >10=performant
Sa {2,4,6,7} : nucleaire absolu=2, egalitaire=4, communautaire=6, souche=7

Reponds UNIQUEMENT en JSON pur sans markdown.`;

const USER = `WP: ${wp_id} | Cas: ${cas} | Periode: ${periode} | Cluster: ${cluster}

Sources pour codage independant:
${sources_neutres.slice(0, 2500)}

Format obligatoire:
{
  "wp_id": "${wp_id}",
  "codeur": "CONV-B",
  "date_codage": "${new Date().toISOString()}",
  "variables_conv_b": {
    "E_split": {"valeur": 0.0, "indicateur": "...", "source_utilisee": "...", "justification": "..."},
    "gamma":   {"valeur": 0.0, "indicateur": "...", "source_utilisee": "...", "justification": "..."},
    "A_d_eff": {"valeur": 0.0, "indicateur": "...", "source_utilisee": "...", "justification": "..."},
    "A_r_c":   {"valeur": 0.0, "indicateur": "...", "source_utilisee": "...", "justification": "..."},
    "A_r_ne":  {"valeur": 0.0, "indicateur": "...", "source_utilisee": "...", "justification": "..."},
    "Cs":      {"valeur": 0.0, "indicateur": "...", "source_utilisee": "...", "justification": "..."},
    "L_t":     {"valeur": 0.0, "indicateur": "...", "source_utilisee": "...", "justification": "..."},
    "EROI":    {"valeur": 0.0, "indicateur": "...", "source_utilisee": "...", "justification": "..."},
    "Sa":      {"valeur": 0,   "source_utilisee": "Todd (1990)", "justification": "..."}
  }
}`;

const payload = JSON.stringify({
  model: "claude-sonnet-4-20250514", max_tokens: 2000,
  system: SYSTEM, messages: [{ role: "user", content: USER }]
});

const conv_b_data = await new Promise((resolve, reject) => {
  const req = https.request({
    hostname: "api.anthropic.com", path: "/v1/messages", method: "POST",
    headers: { "Content-Type": "application/json",
      "x-api-key": ANTHROPIC_API_KEY, "anthropic-version": "2023-06-01" }
  }, (res) => {
    let body = "";
    res.on("data", c => body += c);
    res.on("end", () => {
      try {
        if (res.statusCode !== 200) { reject(new Error(`HTTP ${res.statusCode}: ${body.slice(0,200)}`)); return; }
        const t = JSON.parse(body).content?.[0]?.text || "{}";
        resolve(JSON.parse(t.replace(/```json|```/g,"").trim()));
      } catch(e) { reject(new Error(`Parse CONV-B: ${e.message}`)); }
    });
  });
  req.setTimeout(90000, () => { req.destroy(); reject(new Error("Timeout 90s")); });
  req.on("error", reject);
  req.write(payload); req.end();
});

// Sauvegarder fiche CONV-B — conversion variables_conv_b → variables
// kappa_calculator.py attend le format standard {variables: {var: {valeur: x}}}
const fiche_b_path = `/tmp/${wp_id}_fiche_conv_b.json`;
const vars_conv_b_raw = conv_b_data.variables_conv_b || {};
const fiche_b_normalized = {
  wp_id: conv_b_data.wp_id || wp_id,
  codeur: "CONV-B",
  date_codage: conv_b_data.date_codage || new Date().toISOString(),
  variables: Object.fromEntries(
    Object.entries(vars_conv_b_raw).map(([k, v]) => [
      k, { valeur: typeof v === "object" ? v.valeur : v }
    ])
  ),
  sa: conv_b_data.variables_conv_b?.Sa?.valeur ?? data.llm_context?.sa ?? null
};
fs.writeFileSync(fiche_b_path, JSON.stringify(fiche_b_normalized, null, 2));

// Construire fiche CONV-E pour kappa_calculator
const fiche_e_data = {
  wp_id, codeur: "CONV-E",
  date_codage: new Date().toISOString(),
  variables: Object.fromEntries(
    Object.entries(fiche_input).map(([k, v]) => [
      k, { valeur: v.valeur ?? v.valeur_normative_v62 ?? null }
    ])
  ),
  sa: data.llm_context?.sa ?? null
};
const fiche_e_path = `/tmp/${wp_id}_fiche_conv_e_kappa.json`;
fs.writeFileSync(fiche_e_path, JSON.stringify(fiche_e_data, null, 2));

// Lancer kappa calculator
const cci_path = `/tmp/${wp_id}_cci_result.json`;
let cci_result = null;
let cci_error  = null;
try {
  execSync(`/usr/bin/python3 ${SCRIPTS}/mepa_kappa_calculator.py ${fiche_e_path} ${fiche_b_path} ${cci_path}`,
    { encoding: "utf8", maxBuffer: 5*1024*1024 });
  cci_result = JSON.parse(execSync(`cat ${cci_path}`, { encoding: "utf8" }));
} catch(e) { cci_error = e.message; }

const cci_global  = cci_result?.cci ?? null;
const verdict_cci = cci_result?.verdict ?? "NON_CALCULE";
const desaccords  = (cci_result?.details || []).filter(d => d.accord === false);
const need_human  = desaccords.some(d =>
  d.action === "CONFRONTATION_OBLIGATOIRE" || d.action === "CONFRONTATION_SOURCES");

// Scores resolus automatiquement
const scores_resolus = {};
for (const d of cci_result?.resolution || []) {
  if (d.action === "MOYENNE") scores_resolus[d.variable] = d.valeur_retenue;
}

return {
  json: {
    ...data,
    conv_b_data, fiche_b_path, cci_result, cci_global, verdict_cci,
    desaccords, scores_resolus, need_human_review: need_human, cci_error,
    message: cci_error
      ? `[ERREUR CCI] ${cci_error.slice(0,150)}`
      : `CCI=${cci_global?.toFixed(3)} -- ${verdict_cci} -- humain requis: ${need_human ? "OUI" : "NON"}`
  }
};

// NOEUD 8c -- WAIT Validation CCI Humaine
// Guide Survie : intervention humaine si desaccord > 2*seuil ou variable categorielle
"use strict";
const data = $input.item.json;
return {
  json: {
    ...data,
    status: "WAIT_CCI_VALIDATION",
    instructions_humain: (data.desaccords || []).map(d => ({
      variable: d.variable, action: d.action,
      val_conv_e: d.val_a, val_conv_b: d.val_b, detail: d.detail
    })),
    message: `[WAIT] ${(data.desaccords||[]).length} desaccord(s) CCI necessitent validation humaine avant simulation.`
  }
};

// NOEUD 8d -- Injection Valeurs Resolues (post-CCI) dans runner_config
// Protocole : runner tourne sur valeurs FINALES apres resolution inter-codeurs
"use strict";
const data = $input.item.json;

const scores_resolus = data.scores_resolus || {};
const fiche_input    = data.llm_context?.mepa_full_vars || {};

// Construire les commandes avec les valeurs resolues
// Priorite : scores_resolus (post-CCI) > valeur fiche CONV-E
const cmd_base = { ...(data.llm_context?.cmd_brut || {}) };

// Mapper variables MEPA -> commandes runner
const VAR_TO_CMD = {
  'gamma':   'gamma',   // γ organisationnel → cmd.gamma
  'A_r_c':   'Rc',      // répression classique → cmd.Rc
  'A_r_ne':  'Rn',      // répression numérique → cmd.Rn
  'E_split':  'E',      // fracture élite → cmd.E [CORRECTIF A3]
  'Cs':      'Mob',     // crédibilité/mobilisation → cmd.Mob [CORRECTIF A3]
  // A_d_eff → cmd.R : CONV-E code R directement dans commandes_mises_a_jour
  // L_t → conditions_initiales.L0 : géré séparément ci-dessous
};

// Correction L0 depuis scores_resolus si L_t résolu post-CCI [CORRECTIF A3]
if (scores_resolus['L_t'] !== undefined) {
  let runner_cfg_l0 = {};
  try { runner_cfg_l0 = JSON.parse(data.runner_config_json || "{}"); } catch(e) {}
  if (!runner_cfg_l0.y0) runner_cfg_l0.y0 = [1.0, 0.3, 0.1, 4.0];
  if (Array.isArray(runner_cfg_l0.y0)) {
    runner_cfg_l0.y0[1] = scores_resolus['L_t']; // index 1 = L0
  } else if (typeof runner_cfg_l0.y0 === 'object') {
    runner_cfg_l0.y0['L'] = scores_resolus['L_t'];
    runner_cfg_l0.y0['L0'] = scores_resolus['L_t'];
  }
}

for (const [var_name, cmd_key] of Object.entries(VAR_TO_CMD)) {
  if (scores_resolus[var_name] !== undefined) {
    cmd_base[cmd_key] = scores_resolus[var_name];
  }
}

// Mettre a jour le runner_config_json avec les valeurs resolues
let runner_config = {};
try {
  runner_config = JSON.parse(data.runner_config_json || "{}");
} catch(e) {}

// Appliquer les corrections de commandes
if (Object.keys(cmd_base).length > 0) {
  runner_config.cmd = { ...(runner_config.cmd || {}), ...cmd_base };
}

// Sauvegarder config mise a jour
const { execSync } = require("child_process");
const fs = require("fs");
const config_path = `/tmp/${data.wp_id}_runner_config.json`;
const config_json_updated = JSON.stringify(runner_config);
fs.writeFileSync(config_path, config_json_updated);

return {
  json: {
    ...data,
    runner_config_json: config_json_updated,
    runner_config_path: config_path,
    valeurs_finales: {
      ...Object.fromEntries(
        Object.entries(fiche_input).map(([k, v]) => [
          k, scores_resolus[k] ?? v.valeur ?? v.valeur_normative_v62 ?? null
        ])
      ),
      ...scores_resolus
    },
    cci_global:   data.cci_global   ?? null,
    cci_result:   data.cci_result   ?? null,
    verdict_cci:  data.verdict_cci  ?? null,
    message: `Valeurs resolues injectees -- ${Object.keys(scores_resolus).length} variables resolues par CCI`
  }
};

// NŒUD 3 — Write Config File (No-FS via stdin)
// Architecture No-FS : transmet runner_config_json via stdin au lieu d'écriture disque directe
// Le runner Python reçoit le JSON sur stdin si aucun chemin fourni en arg

"use strict";
const data = $input.item.json;

if (data.statut_audit === "DONNEES_INSUFFISANTES") {
  return { json: { ...data, status: "NC_BLOQUANT" } };
}

const configJson = data.runner_config_json;
if (!configJson) throw new Error(`[N3] runner_config_json absent — wp_id=${data.wp_id}`);

const MEPA_SCRIPTS_DIR = $env.MEPA_SCRIPTS_DIR || "/data/mepa/scripts";
const wp_id       = data.wp_id;
const configPath  = data.runner_config_path || `/tmp/${wp_id}_runner_config.json`;
const resultPath  = data.result_path        || `/tmp/${wp_id}_result.json`;
const n1Path      = data.n1_path            || `/tmp/${wp_id}_n1_sensitivity.json`;

// No-FS : passer le JSON via echo | /usr/bin/python3 (heredoc shell — évite writeFileSync)
// Le runner accepte le JSON sur stdin quand l'arg est "-"
const runner_cmd = `echo '${configJson.replace(/'/g, "'\\''")}' | /usr/bin/python3 ${MEPA_SCRIPTS_DIR}/mepa_runner_v2_gamma.py - ${resultPath}`;
const n1_cmd     = `echo '${configJson.replace(/'/g, "'\\''")}' | /usr/bin/python3 ${MEPA_SCRIPTS_DIR}/mepa_sensitivity_n1.py - ${n1Path}`;

return {
  json: {
    status:             "CONFIG_READY",
    statut_audit:       data.statut_audit,
    wp_id,
    runner_config_json: configJson,
    runner_config_path: configPath,
    result_path:        resultPath,
    n1_path:            n1Path,
    runner_cmd,
    n1_cmd,
    llm_context:        data.llm_context    || {},
    audit_log:          data.audit_log      || {},
    nc_non_bloquantes:  data.nc_non_bloquantes || [],
    cci_global:         data.cci_global  ?? null,
