              || _items.find(i => i.json.rapport_n1 != null)?.json
              || {};

// Données fusionnées
const data = { ..._dataMain };

// rapport_n1 : priorité branche 5b, fallback payload existant (cas révision)
let rapport_n1 = _dataN1.rapport_n1 || _dataMain.rapport_n1 || null;
const wp_id       = data.wp_id;
const ctx         = data.llm_context || {};
