  ? tableau_s2.map(r => `t=${r.t}: F=${r.F?.toFixed(4)||"?"} R=${r.R?.toFixed(4)||"?"} FR=${r.FR?.toFixed(4)||"?"}`).join("\n")
  : "Non disponible";

const prompt_conva = `Tu es CONV-A (Rédacteur MEPA V6.2 Fortifiée).
