    robustesse_n1: cert.robustesse_n1, robustesse_n2: cert.robustesse_n2,
    concordance: cert.concordance, scores_resolus: cert.scores_resolus,
    verdict_conv_b: cert.verdict_conv_b, popper: cert.popper,
    raison_non_certifie: cert.raison_non_certifie,
    generated_at: new Date().toISOString()
  }
};
archived.passeport = w(`${dirs.passeports}/${wp_id}_passeport.json`, JSON.stringify(passeport_final, null, 2));

// Passeport compact CONV-D (<500 chars) -- format Architecture_Conversations
const popper_rf1 = data.popper?.prediction_applicable === "RF1" ? data.popper?.condition_observation : null;
const popper_rf2 = data.popper?.prediction_applicable === "RF2" ? data.popper?.condition_observation : null;
const passeport_compact = {
  wp_id, cluster,
  sa:           data.result_data?.meta?.sa ?? null,
  traj_attendue: data.result_data?.meta?.trajectoire_attendue || "?",
  traj_diagn:   sim.traj || "?",
  concordant:   cert.concordance ?? false,
  robustesse:   cert.robustesse_n1 || "?",
  t_b:          sim.t_bascule ?? null,
  dC_rel:       sim.dC_rel ?? null,
  dI_rel:       sim.dI_rel ?? null,
  CCI:          cert.cci_global ?? null,
  RF1:          popper_rf1,
  RF2:          popper_rf2,
  p6_final:     data.result_data?.params?.p6 ?? null,
  statut_cert:  cert.statut || "WP_EXPLORATOIRE",
  alertes:      data.anomalies_conv_b || []
};
archived.passeport_compact = w(`${dirs.certification}/${wp_id}_passeport_compact.json`,
  JSON.stringify(passeport_compact));

return {
  json: {
    status: "ARCHIVE_CERTIFIE", wp_id,
    statut_certification: cert.statut, cci_global: cert.cci_global,
    robustesse_n1: cert.robustesse_n1, concordance: cert.concordance,
    verdict_conv_b: data.verdict_conv_b, archived, passeport_compact,
    message: `[WF2 COMPLET] ${wp_id} -> ${cert.statut} | CCI:${cert.cci_global?.toFixed(3)??"null"} | CONV-B:${data.verdict_conv_b||"?"}`
  }
};

// NŒUD CONV-E — Codage historique des 6 variables continues
// Position : après Nœud B (décodage JSON), avant Nœud 2 (audit C1-C13)
// Double aveugle garanti : ce nœud écrit variables[k].valeur
// Le Nœud 8a (CONV-B) filtre activement ces valeurs — aucune contamination
// Correctif architecture — 2026-03-16

"use strict";
const https = require("https");

const data  = $input.item.json;
const wp_id = data.wp_id;
const ANTHROPIC_API_KEY = $env.ANTHROPIC_API_KEY;

// ── Extraire le contexte de la fiche ────────────────────────────────────────
const cas             = data.cas             || "";
const periode         = data.periode         || "";
const cluster         = data.cluster         || "";
const traj_attendue   = data.trajectoire_attendue || "";
const sa              = data.sa              ?? null;
const sa_type         = data.sa_type_todd    || "";
const vars_fiche      = data.variables       || {};
const sources         = data.sources_utilisees || [];
const defi            = data.defi_mepa       || "";
const alertes         = data.alertes_conv_a  || [];

// ── Variables hardcodées (EROI, A_r_ne, Sa) — ne pas recoder ───────────────
const vars_hardcodes = {};
for (const [k, v] of Object.entries(vars_fiche)) {
  if (v.valeur !== null && v.valeur !== undefined &&
      (String(v.source_id || "").includes("hardcod") ||
       String(v.source_id || "").includes("normative") ||
       String(v.source_id || "").includes("V6.2") ||
       String(v.origine  || "").toUpperCase().includes("HARDCOD") ||
       String(v.source_id || "").includes("Todd"))) {
    vars_hardcodes[k] = v.valeur;
  }
}

// ── Variables à coder — celles avec valeur: null ────────────────────────────
const vars_a_coder = Object.fromEntries(
  Object.entries(vars_fiche)
    .filter(([k, v]) => v.valeur === null || v.valeur === undefined)
    .map(([k, v]) => [k, {
      echelle:            v.echelle,
      origine:            v.origine,
      source_id:          v.source_id,
      niveau_source:      v.niveau_source,
      sanity_check:       v.sanity_check,
      valeur_normative:   v.valeur_normative_v62
    }])
);

// ── Commandes actuelles (valeurs normatives — à mettre à jour post-codage) ──
const cmd_actuel = data.commandes || {};

// ── Sources disponibles ──────────────────────────────────────────────────────
const sources_str = sources.slice(0, 8).map(s =>
  typeof s === "object"
    ? `[${s.id}] ${s.titre} (${s.type}) — variables: ${(s.variables_concernees || []).join(", ")}`
    : String(s)
).join("\n");

const SYSTEM = `Tu es CONV-E, l'Historien-Codeur du projet MEPA V6.2.
Ta mission exclusive : coder les variables continues d'une fiche WP JSON.
Tu ne simules pas. Tu ne rédiges pas de WP. Tu codes uniquement les variables null.

RÈGLE ABSOLUE NOMENCLATURE :
- "gamma" = clé JSON (dans le JSON uniquement)
- "γ" = symbole dans les justifications textuelles
- "g" = INTERDIT partout

GRILLE D'ANCRAGE V6.2 :
E_split [0,1] : 0.0-0.2=cohésion élite, 0.4-0.6=fracture naissante, 0.8-1.0=fracture critique
gamma [0,1] : 0.0-0.2=désorganisé, 0.4-0.6=organisation partielle, 0.8-1.0=forte
A_d_eff [0,10] : 0-2=effondrement État, 4-6=trappe à dette, 8-10=surplus
A_r_c [0,1] : 0.0-0.2=absente, 0.4-0.6=sélective, 0.8-1.0=massive
A_r_ne [0,1] : 0.0-0.2=absente, 0.4-0.6=partielle, 0.8-1.0=totale
Cs [0,1] : 0.0-0.2=effondrée, 0.4-0.6=contestée, 0.8-1.0=solide
L_t [0,1] : 0.0-0.2=effondrée, 0.4-0.6=conditionnelle, 0.8-1.0=solide

MAPPING CMD (à renseigner dans commandes_mises_a_jour) :
E_split → cmd.E (direct)
gamma → cmd.gamma (direct)
A_d_eff → cmd.R (normalisé — coder R dans [0,1] proportionnel à A_d_eff/10, ajusté au contexte)
A_r_c → cmd.Rc (direct)
A_r_ne → cmd.Rn (direct)
Cs → cmd.Mob (direct — crédibilité/mobilisation sociale)
L_t → conditions_initiales.L0 (direct)

VARIABLES HARDCODÉES (ne pas recoder) :
${JSON.stringify(vars_hardcodes)}

FORMAT DE RÉPONSE : JSON pur, sans markdown, sans backticks.`;

const USER = `WP : ${wp_id} | Cas : ${cas} | Période : ${periode} | Cluster : ${cluster}
Trajectoire attendue : ${traj_attendue} | Sa : ${sa} (${sa_type})
Défi MEPA : ${defi.slice(0, 300)}
Alertes : ${JSON.stringify(alertes).slice(0, 200)}

SOURCES DISPONIBLES :
${sources_str}

VARIABLES À CODER (valeur = null) :
${JSON.stringify(vars_a_coder, null, 2).slice(0, 3000)}

COMMANDES ACTUELLES (valeurs normatives à mettre à jour) :
${JSON.stringify({
  E: cmd_actuel.E, gamma: cmd_actuel.gamma, R: cmd_actuel.R,
  Mob: cmd_actuel.Mob, Rc: cmd_actuel.Rc, Rn: cmd_actuel.Rn
})}

CONDITIONS INITIALES ACTUELLES :
${JSON.stringify(data.conditions_initiales || {})}

Produis un JSON avec exactement cette structure :
{
  "codeur": "CONV-E",
  "date_codage": "${new Date().toISOString().split("T")[0]}",
  "variables_codees": {
    "E_split": {"valeur": <float>, "justification": "<2-3 phrases avec γ si gamma, indicateurs chiffrés>", "sanity_check": {"indicateur": "<source>", "valeur_indicateur": "<valeur>", "coherence": "CONFIRMÉ|À VÉRIFIER|DIVERGENCE"}},
    "gamma":   {"valeur": <float>, "justification": "<utilise γ dans le texte>", "sanity_check": {"indicateur": "<source>", "valeur_indicateur": "<valeur>", "coherence": "CONFIRMÉ|À VÉRIFIER|DIVERGENCE"}},
    "A_d_eff": {"valeur": <float>, "justification": "<indicateurs chiffrés obligatoires>", "sanity_check": {"indicateur": "<source>", "valeur_indicateur": "<valeur>", "coherence": "CONFIRMÉ|À VÉRIFIER|DIVERGENCE"}},
    "A_r_c":   {"valeur": <float>, "justification": "<source explicite>", "sanity_check": {"indicateur": "<source>", "valeur_indicateur": "<valeur>", "coherence": "CONFIRMÉ|À VÉRIFIER|DIVERGENCE"}},
    "Cs":      {"valeur": <float>, "justification": "<source explicite>", "sanity_check": {"indicateur": "<source>", "valeur_indicateur": "<valeur>", "coherence": "CONFIRMÉ|À VÉRIFIER|DIVERGENCE"}},
    "L_t":     {"valeur": <float>, "justification": "<source explicite>", "sanity_check": {"indicateur": "<source>", "valeur_indicateur": "<valeur>", "coherence": "CONFIRMÉ|À VÉRIFIER|DIVERGENCE"}}
  },
  "commandes_mises_a_jour": {
    "E": <float E_split>, "gamma": <float gamma>,
    "R": <float normalisé A_d_eff>, "Mob": <float Cs>,
    "Rc": <float A_r_c>, "Rn": <float A_r_ne hardcodé>
  },
  "L0_mis_a_jour": <float L_t>,
  "resume_coherence": "<3-5 phrases — compatibilité scores avec trajectoire attendue et cluster>"
}`;

const payload = JSON.stringify({
  model: "claude-sonnet-4-20250514",
  max_tokens: 3000,
  system: SYSTEM,
  messages: [{ role: "user", content: USER }]
});

// ── Appel API Anthropic ──────────────────────────────────────────────────────
const conv_e_result = await new Promise((resolve, reject) => {
  const req = https.request({
    hostname: "api.anthropic.com",
    path: "/v1/messages",
    method: "POST",
    headers: {
      "Content-Type": "application/json",
      "x-api-key": ANTHROPIC_API_KEY,
      "anthropic-version": "2023-06-01"
    }
  }, (res) => {
    let body = "";
    res.on("data", c => body += c);
    res.on("end", () => {
      try {
        if (res.statusCode !== 200) { reject(new Error(`HTTP ${res.statusCode}: ${body.slice(0,200)}`)); return; }
        const raw = JSON.parse(body).content?.[0]?.text || "{}";
        const clean = raw.replace(/```json|```/g, "").trim();
        resolve(JSON.parse(clean));
      } catch(e) {
        reject(new Error(`Parse CONV-E: ${e.message} | raw: ${body.slice(0,200)}`));
      }
    });
  });
  req.setTimeout(120000, () => { req.destroy(); reject(new Error("Timeout 120s")); });
  req.on("error", reject);
  req.write(payload);
  req.end();
});

// ── Injecter les valeurs codées dans la fiche ────────────────────────────────
const vars_codees  = conv_e_result.variables_codees  || {};
const cmd_updates  = conv_e_result.commandes_mises_a_jour || {};
const l0_update    = conv_e_result.L0_mis_a_jour;

// Mettre à jour variables[k].valeur
const vars_updated = { ...vars_fiche };
for (const [k, v] of Object.entries(vars_codees)) {
  if (vars_updated[k]) {
    vars_updated[k] = {
      ...vars_updated[k],
      valeur:       v.valeur,
      justification: v.justification,
      sanity_check: { ...vars_updated[k].sanity_check, ...v.sanity_check },
      codeur:       "CONV-E",
      date_codage:  conv_e_result.date_codage
    };
  }
}

// Mettre à jour les commandes — mapping sélectif CONV-E
// RÈGLE V6.2 : E, gamma, Rc, Rn → mapping libre depuis variables codées
// R (A_d_eff) et Mob (Cs) → NE PAS écraser les valeurs normatives corpus
// T, Ref, Pop, EROI → structurels, jamais modifiés par CONV-E
const CMD_MAPPING_LIBRE = ["E", "gamma", "Rc", "Rn"];
const cmd_updated = { ...cmd_actuel };
for (const key of CMD_MAPPING_LIBRE) {
  if (cmd_updates[key] !== undefined && cmd_updates[key] !== null) {
    cmd_updated[key] = cmd_updates[key];
  }
}
// R et Mob : logguer la valeur CONV-E mais préserver la valeur normative
const r_conv_e   = cmd_updates["R"]   ?? null;
const mob_conv_e = cmd_updates["Mob"] ?? null;
if (r_conv_e !== null) {
  console.error("[CONV-E] cmd.R propose par CONV-E = " + r_conv_e + " -- valeur normative corpus preservee : " + cmd_actuel.R);
}
if (mob_conv_e !== null) {
  console.error("[CONV-E] cmd.Mob propose par CONV-E = " + mob_conv_e + " -- valeur normative corpus preservee : " + cmd_actuel.Mob);
}

// Mettre à jour L0 dans conditions_initiales
const ci_updated = { ...(data.conditions_initiales || {}) };
if (l0_update !== undefined && l0_update !== null) {
  ci_updated.L0 = l0_update;
}

// ── Retourner la fiche enrichie ──────────────────────────────────────────────
// Champs pipeline (non transmis dans la fiche racine — évite erreur C9)
const _conv_e_meta = {
  conv_e_raw:       conv_e_result,
  resume_coherence: conv_e_result.resume_coherence || "",
  nb_vars_codees:   Object.keys(vars_codees).length
};

return {
  json: {
    ...data,
    // Champs fiche — autorisés par RACINE_AUTORISEES
    variables:            vars_updated,
    commandes:            cmd_updated,
    conditions_initiales: ci_updated,
    statut:               "CODAGE CONV-E — EN ATTENTE AUDIT CONV-B",
    date_codage:          conv_e_result.date_codage || new Date().toISOString().split("T")[0],
    codeur:               "CONV-E",
    // Champs pipeline — préfixe _ exclu de la fiche mais lisibles par les nœuds suivants
    _conv_e_meta,
    _pipeline_message: `[CONV-E] ${wp_id} — ${Object.keys(vars_codees).length} variables codées`
  }
};

// NŒUD C — Nettoyage /tmp/ entre passes
// Supprime tous les fichiers /tmp/{wp_id}_* de la passe précédente
// Garantit l'isolation entre passes successives sur le même WP
"use strict";
const { execSync } = require("child_process");
const data  = $input.item.json;
const wp_id = data.wp_id || "WP-INCONNU";

let cleaned = [];
let errors  = [];

// Liste des fichiers /tmp/ créés par le pipeline
const patterns = [
  `_runner_config.json`,
  `_result.json`,
  `_n1_sensitivity.json`,
  `_fiche_conv_b.json`,
  `_fiche_conv_e_kappa.json`,
  `_cci_result.json`,
  `_passeport.json`,
  `_n2_optimiste.json`,
  `_n2_pessimiste.json`,
  `_n2_optimiste_result.json`,
  `_n2_pessimiste_result.json`,
  `_revision_counter.txt`
];

for (const suffix of patterns) {
  const path = `/tmp/${wp_id}${suffix}`;
  try {
    execSync(`rm -f ${path}`);
    cleaned.push(path);
  } catch(e) {
    errors.push(`${path}: ${e.message.slice(0,50)}`);
  }
}

return {
  json: {
    ...data,
    cleanup: { cleaned: cleaned.length, errors },
    message: `[CLEANUP] ${wp_id} — ${cleaned.length} fichiers /tmp/ supprimés`
  }
};
